import java.util.Scanner;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine(); // Read the entire line including whitespaces

        char[] buffer = new char[10];
        int length = Math.min(name.length(), buffer.length); // Ensure that we don't exceed buffer size

        // Safely copy user input into the fixed-size buffer
        for (int i = 0; i < length; i++) {
            buffer[i] = name.charAt(i);
        }

        System.out.println("Buffer contents: " + new String(buffer));

        scanner.close();
    }
}

